xinshengCustomCss:
/* 终极扁平化白纸 */
.xt-root { --xt-bg: #fff; --xt-text: #333; --xt-radius: 16px; font-family: -apple-system, BlinkMacSystemFont, "Helvetica Neue", sans-serif; box-shadow: 0 4px 20px rgba(0,0,0,.08); border: none; }
.xt-text { background: transparent !important; border: none !important; padding: 0 !important; box-shadow: none !important; color: #333; font-size: 15px; margin-bottom: 16px; display: block; }
/* 1. 时间 */
.xt-text:nth-of-type(1) { text-align: center; font-size: 12px; color: #8e8e93; margin-top: 10px; margin-bottom: 55px; position: relative; }
.xt-text:nth-of-type(1)::after { content: "‧₊𐙚ﾟ日記帳♡˖ ⊹"; position: absolute; left: 9px; bottom: -45px; font-size: 24px; font-weight: bold; color: #000; letter-spacing: 0; }
/* 2. 天气 3. 温度 */
.xt-text:nth-of-type(2), .xt-text:nth-of-type(3) { display: inline-block; font-size: 14px; margin-left: 14px;color: #666; margin-bottom: 16px; }
.xt-text:nth-of-type(2)::before { content: ""; display: inline-block; width: 4px; height: 15px; background-color: #d1d1d6; border-radius: 2px; margin-right: 8px; vertical-align: -3px; }
.xt-text:nth-of-type(2)::after { content: " | "; margin: 0 2px; position: relative; top: -1px}
.xt-text:nth-of-type(3) { margin-left: 2px !important; }
/* 4. 日记正文修补 */
.xt-text:nth-of-type(4) { display: block; line-height: 1.6; margin-bottom: 16px;margin-left: 14px;margin-right: 16px;}
/* 5. 心情 6. 其他标签 */
.xt-text:nth-of-type(5), .xt-text:nth-of-type(6) { display: inline-block; color: #eab308 !important; margin-right: -7px; margin-bottom: 24px;margin-left: 12px;}
.xt-text:nth-of-type(5)::before { content: "#"; .xt-text:nth-of-type(6)}
/* 7. 阴暗想法 (待办1)  */
.xt-text:nth-of-type(7) { position: relative; padding-left: 34px !important; color: #8e8e93 !important; text-decoration: line-through; margin-top: 28px; margin-bottom: 12px; display: block;margin-left: 11px; }
.xt-text:nth-of-type(7)::before { content: "待办事项"; position: absolute; left: 2px; top: -35px; font-size: 18px; font-weight: bold; color: #000; text-decoration: none; }
.xt-text:nth-of-type(7)::after { content: ""; position: absolute; left: 4px; top: 3px; width: 20px; height: 20px; border: 1.5px solid #d1d1d6; border-radius: 50%; box-sizing: border-box; }

/* 8. 接下来行动 (待办2) - 撑开空间 + 纯白苹果气泡 */
.xt-text:nth-of-type(8) { position: relative; padding-left: 34px !important; margin-bottom: 60px; display: block; margin-left: 11px;}
.xt-text:nth-of-type(8)::before { content: "✓"; position: absolute; left: 4px; top: 2px; width: 20px; height: 20px; background-color: #eab308; color: #fff; font-size: 12px; line-height: 20px; text-align: center; border-radius: 50%; font-weight: bold; }
.xt-text:nth-of-type(8)::after {
   content: "剪切 ｜ 拷贝 ｜ 粘贴 ｜ 简⇌繁 ｜ 自动填充 ｜ >";
   position: absolute;
   left: -3px;
   bottom: -57px;
   background-color: #fff;
   color: #000;
   font-size: 13px;
   padding: 7px 14px;
   border-radius: 10px;
   white-space: nowrap;
   z-index: 10;
   box-shadow: 0 0px 7px rgba(0,0,0,0.1);
   font-weight: 400;
   border: 1px solid #e5e5ea;
}

/* 9. 黄色高亮 - 往下躲开气泡 */
.xt-text:nth-of-type(9) { display: inline-block; background-color: rgba(250,204,21,0.3) !important; padding: 1px 4px !important; margin-left: 15px; margin-bottom: 25px; margin-top: 10px; position: relative; box-shadow: -2px 0 0 #eab308, 2px 0 0 #eab308; }
.xt-text:nth-of-type(9)::before { content: ''; position: absolute; width: 7px; height: 7px; background-color: #eab308; border-radius: 50%; left: -4.5px; top: -4px; }
.xt-text:nth-of-type(9)::after { content: ''; position: absolute; width: 7px; height: 7px; background-color: #eab308; border-radius: 50%; right: -4.5px; bottom: -4px; }
/* 10. 当前环境 (给屁股下面留出60px的空地放图标！) */
.xt-text:nth-of-type(10) { background: #f2f2f7 !important; border-radius: 12px; padding: 12px 16px !important; margin-top: -5px; margin-bottom: 60px !important; font-size: 14px; position: relative; padding-top: 36px !important; color: #8e8e93; display: block; }
.xt-text:nth-of-type(10)::before { content: "当前环境"; position: absolute; top: 12px; left: 16px; font-size: 15px; font-weight: 600; color: #000; }
/* 1. 给整张白纸上下腾出更多空间！ */
.xt-root {
   position: relative;
   padding-top: 46px !important;
   padding-bottom: 20px !important; /* 底部留出20px空地！ */
}

/* 2. 顶部左边：返回按钮贴图 */
.xt-root::before {
   content: "";
   position: absolute;
   top: 23px;
   left: 16px;
   width: 85px;
   height: 29px;
   background-image: url("https://nos.netease.com/ysf/ac8f841b7092d10bf6e8f76b8def3649.jpeg");
   background-size: contain;
   background-repeat: no-repeat;
   background-position: left center;
}

/* 3. 顶部右边：四个小图标贴图 (寄生在时间身上) */
.xt-text:nth-of-type(1)::before {
   content: "";
   position: absolute;
   top: -52px;
   right: 0;
   width: 165px;
   height: 69px;
   background-image: url("https://nos.netease.com/ysf/68de3b612e78d76c82419a0daa1d10ae.jpeg");
   background-size: contain;
   background-repeat: no-repeat;
   background-position: right center;
}

/* 4. 底部工具栏 (寄生在第10段身上，往下悬浮！) */
.xt-text:nth-of-type(10)::after {
   content: "";
   position: absolute;
   bottom: -50px; /* 悬在灰框正下方 */
   left: 0%;
   width: 100%;
   height: 32px;
   background-image: 
      url("https://nos.netease.com/ysf/7f6e0c662c417d87d0a01670d98fc3d8.jpeg"),

url("https://nos.netease.com/ysf/9c4e0b6658bec04188727cf8e750700e.jpeg"),

url("https://nos.netease.com/ysf/b389f00f9375cd739ec05ac0997b3dbe.jpeg"),

url("https://nos.netease.com/ysf/5672f34cc5ba38b7a4ab5ba721164ea0.jpeg");
   background-position: 
      2% center,
      33% center,
      66% center,
      98% center;
   /* 图标放大 */
   background-size: 42px 45px, 52px 50px, 47px 52px, 55px 51px;
   background-repeat: no-repeat;
}

